import { awaitSynapse } from 'synapse-storage/react'
import { createSynapse } from 'synapse-storage/utils'

// Initialization may take time (IndexedDB, loading from the server, etc.)
const configSynapse = createSynapse(async () => {
  const data = await fetch('/api/config').then((r) => r.json())
  const storage = new MemoryStorage({ name: 'config', initialState: data })
  return {
    storage,
    dispatcher: new ConfigDispatcher(storage),
    selectors: new ConfigSelectors(storage),
  }
})

// Create an awaiter — it accepts a handle (thenable)
const awaiter = awaitSynapse(configSynapse, {
  loadingComponent: <div>Loading...</div>,
  errorComponent: (error) => <div>Error: {error.message}</div>,
})

// HOC: shows loadingComponent while the storage isn't ready
// The component renders ONLY when the storage is fully initialized

function MyComponent() {
  // The storage is guaranteed to be ready — it can be used safely
  const store = awaiter.getStoreIfReady()!
  const value = useSelector(store.selectors.someValue)

  return <div>{value}</div>
}

// Wrap it
const MyComponentWithReady = awaiter.withSynapseReady(MyComponent)

// In JSX — it first shows loading, then the component:
<MyComponentWithReady />

// A hook for manual control over readiness

function StatusPanel() {
  const { isReady, isPending, isError, store, error } = awaiter.useSynapseReady()

  if (isPending) return <div>Loading...</div>
  if (isError)   return <div>Error: {error?.message}</div>
  if (isReady)   return <div>Store ready! State: {JSON.stringify(store.storage.getStateSync())}</div>
}

// Fields of the returned object:
// isReady:   boolean — the storage is initialized
// isPending: boolean — waiting for initialization
// isError:   boolean — initialization error
// store:     SynapseStore | undefined
// error:     Error | null

// Can be used outside React components

// Synchronous checks
awaiter.isReady()         // boolean
awaiter.getStatus()       // 'pending' | 'ready' | 'error'
awaiter.getError()        // Error | null
awaiter.getStoreIfReady() // store | undefined

// Asynchronous waiting
const store = await awaiter.waitForReady()

// Callbacks (return an unsubscribe function)
const unsub = awaiter.onReady((store) => {
  console.log('Store ready!', store.storage.getStateSync())
})

const unsub2 = awaiter.onError((error) => {
  console.error('Init failed:', error.message)
})

// If the storage is already ready — onReady fires immediately

// Cleanup
awaiter.destroy()

// awaitSynapse — a React wrapper around createSynapseAwaiter
// Adds: withSynapseReady (HOC) and useSynapseReady (hook)
// Proxies: waitForReady, isReady, getStoreIfReady, onReady, onError, getStatus, getError, destroy

// For vanilla JS / Node.js / without React — use createSynapseAwaiter directly:
import { createSynapseAwaiter } from 'synapse-storage/utils'
const awaiter = createSynapseAwaiter(configSynapse)
// The same programmatic API, but without React hooks

import { MemoryStorage, Selectors } from 'synapse-storage/core'
import { createSynapse } from 'synapse-storage/utils'
import { useSelector } from 'synapse-storage/react'

interface TodoState {
  todos: Array<{ id: number; text: string; done: boolean }>
  filter: 'all' | 'active' | 'done'
}

// Selectors — class fields, real SelectorAPI right away (eager). Name = field name.
class TodoSelectors extends Selectors<TodoState> {
  readonly todos = this.select((state) => state.todos)
  readonly filter = this.select((state) => state.filter)

  // Combined: depends on todos and filter
  readonly filteredTodos = this.combine([this.todos, this.filter], (todos, filter) => {
    if (filter === 'active') return todos.filter((t) => !t.done)
    if (filter === 'done') return todos.filter((t) => t.done)
    return todos
  })

  readonly doneCount = this.combine([this.todos], (todos) => todos.filter((t) => t.done).length)
}

// createSynapse(factory) → a lazy handle. The factory runs once
// on the first await / ready(), not on import.
const todoSynapse = createSynapse(async () => {
  const storage = new MemoryStorage<TodoState>({
    name: 'todo-basic',
    initialState: { todos: [], filter: 'all' },
  })
  return {
    storage,
    selectors: new TodoSelectors(storage),
  }
})

export type TodoSynapse = Awaited<typeof todoSynapse>

// The handle is a thenable: await triggers the factory and returns the assembled module
const store = await todoSynapse

// The result (basic — without a dispatcher):
store.storage    // IStorage<TodoState> — the storage
store.selectors  // a TodoSelectors instance — fields = SelectorAPI

// The handle itself:
todoSynapse.ready()    // Promise<store> — the same as await
todoSynapse.isReady()  // boolean
todoSynapse.destroy()  // () => Promise<void> — cleanup + memoization reset (the handle is re-creatable)

// useSelector — subscribes to a selector (automatically updates the component)
const todos = useSelector(store.selectors.todos)
const filteredTodos = useSelector(store.selectors.filteredTodos)
const doneCount = useSelector(store.selectors.doneCount)

// Changing the state — through the storage directly
store.storage.set('filter', 'active')

store.storage.update((s) => {
  s.todos.push({ id: Date.now(), text: 'New', done: false })
})

const todoSynapse = createSynapse(async () => {
  const data = await fetch('/api/todos').then((r) => r.json())
  const storage = new MemoryStorage<TodoState>({
    name: 'todo-async',
    initialState: { todos: data, filter: 'all' },
  })
  return {
    storage,
    selectors: new TodoSelectors(storage),
  }
})

import { MemoryStorage, Selectors } from 'synapse-storage/core'
import { createSynapse } from 'synapse-storage/utils'
import { Dispatcher } from 'synapse-storage/reactive'

// Selectors — class fields
class CartSelectors extends Selectors<CartState> {
  readonly items = this.select((s) => s.items)
  readonly discount = this.select((s) => s.discount)
  readonly totalPrice = this.combine([this.items, this.discount], (items, discount) => {
    const sum = items.reduce((acc, i) => acc + i.price * i.qty, 0)
    return sum * (1 - discount / 100)
  })
}

// Dispatcher — actions and watchers as class fields. Action name = field name.
class CartDispatcher extends Dispatcher<CartState> {
  readonly addItem = this.action((store, params: { name: string; price: number }) => {
    store.update((s) => { s.items.push({ id: Date.now(), ...params, qty: 1 }) })
    return params
  })
  readonly setDiscount = this.action((store, percent: number) => {
    store.set('discount', percent)
    return percent
  })
  readonly watchItemCount = this.watcher({ selector: (s) => s.items.length })
}

const cartSynapse = createSynapse(async () => {
  const storage = new MemoryStorage<CartState>({ name: 'cart', initialState })
  return {
    storage,
    dispatcher: new CartDispatcher(storage),
    selectors: new CartSelectors(storage),
  }
})

// this.action((store, params) => result) — a handler in the "recipe" signature.
// The action's payload = the value returned by the handler.
class CartDispatcher extends Dispatcher<CartState> {
  readonly addItem = this.action((store, params: { name: string; price: number }) => {
    store.update((s) => {
      s.items.push({ id: Date.now(), ...params, qty: 1 })
    })
    return params                            // return = payload in the action stream
  })
}

// Calling via store.actions (action name = field name)
store.actions.addItem({ name: 'Hat', price: 1500 })

// actionType is generated from the field name at finalization
store.actions.addItem.actionType  // '[cart]addItem'

// this.watcher — reactively tracks state changes
class CartDispatcher extends Dispatcher<CartState> {
  readonly watchItemCount = this.watcher({
    selector: (state) => state.items.length,        // what to track
    notifyAfterSubscribe: true,                     // call immediately on subscribe
    shouldTrigger: (prev, curr) => prev !== curr,   // filter (optional)
  })
}

// Subscribing — returns an RxJS Observable
const sub = store.dispatcher.watchers.watchItemCount().subscribe((action) => {
  console.log('item count:', action.payload)
})

// Unsubscribe
sub.unsubscribe()

const store = await cartSynapse

store.storage     // IStorage<CartState>
store.selectors   // a CartSelectors instance
store.actions     // { addItem, removeItem, changeQty, setDiscount }
store.dispatcher  // a CartDispatcher instance (dispatch, watchers, action$)

// store.actions — shorthand for store.dispatcher.dispatch
// store.actions.addItem === store.dispatcher.dispatch.addItem

// The stream of all actions (RxJS Observable)
store.dispatcher.actions.subscribe((action) => {
  console.log(action.type, action.payload)
})

import { createSynapseCtx } from 'synapse-storage/react'

// Pass the handle ITSELF (not a call) — the factory starts lazily on the first Provider mount
export const { contextSynapse, useSynapseSelectors, useSynapseActions } =
  createSynapseCtx(cartSynapse, { loadingComponent: <div>Loading...</div> })

import { MemoryStorage, Selectors } from 'synapse-storage/core'
import { createSynapse } from 'synapse-storage/utils'
import { Dispatcher, Effects, ofType } from 'synapse-storage/reactive'
import { debounceTime, switchMap } from 'rxjs/operators'
import { from } from 'rxjs'

class SearchSelectors extends Selectors<SearchState> {
  readonly query = this.select((s) => s.query)
  readonly results = this.select((s) => s.results)
}

class SearchDispatcher extends Dispatcher<SearchState> {
  readonly setQuery = this.action((store, query: string) => { store.set('query', query); return query })
  readonly searchSuccess = this.action((store, results: string[]) => { store.set('results', results); return results })
}

// Effects — a class over Effects<State, Dispatcher>; services through the constructor
class SearchEffects extends Effects<SearchState, SearchDispatcher> {
  constructor(private readonly api: SearchApi) { super() }

  readonly search$ = this.effect((action$, state$, { dispatcher: d }) =>
    action$.pipe(
      ofType(d.setQuery),
      debounceTime(400),
      switchMap((action) => from(this.api(action.payload)).pipe(
        switchMap(async (results) => d.searchSuccess(results)),
      )),
    ),
  )
}

const searchSynapse = createSynapse(async () => {
  const storage = new MemoryStorage<SearchState>({ name: 'search', initialState })
  return {
    storage,
    dispatcher: new SearchDispatcher(storage),
    selectors: new SearchSelectors(storage),
    effects: new SearchEffects(searchApi),   // services — through the constructor
  }
})

// this.effect — a class field; the function receives streams and a context, returns an Observable.
// Services/external stores come through the constructor and are captured in the recipe's closure.
class SearchEffects extends Effects<SearchState, SearchDispatcher> {
  constructor(private readonly api: SearchApi) { super() }

  readonly search$ = this.effect((action$, state$, ctx) => {
    const d = ctx.dispatcher                 // the module's typed dispatcher
    return action$.pipe(
      ofType(d.setQuery),                    // filter by action
      debounceTime(400),
      switchMap((action) => from(this.api(action.payload)).pipe(
        switchMap(async (results) => d.searchSuccess(results)),
      )),
    )
  })

  // Optional teardown — close sockets etc.
  override onDestroy() { /* ... */ }
}

import { ofType, ofTypes } from 'synapse-storage/reactive'

// ofType — filter the stream by a single action type
action$.pipe(
  ofType(d.setQuery),
)

// ofTypes — filter by several types
action$.pipe(
  ofTypes([d.setQuery, d.searchError]),
)

import { ofType, validateMap, fromRequest, apiResult } from 'synapse-storage/reactive'

loadPosts$ = this.effect((action$, state$, { dispatcher: d }) =>
  action$.pipe(
    ofType(d.loadPosts),
    withLatestFrom(selectorObject(state$, { status: (s) => s.api.postsRequest.status })),
    validateMap({
      // gate: don't refetch while a request is already in flight
      validator: ([, { status }]) => ({ conditions: [status !== ApiStatus.Loading], skipAction: () => d.loadPosts.reset() }),
      loadingAction: () => d.loadPosts.loading(),
      errorAction: (err) => d.loadPosts.failure(getErrorMessage(err)),
      apiCall: ([action], { chunkRequest, chunkRequestConsistent }) =>
        fromRequest(this.api.getPosts.request(action.payload)).pipe(
          apiResult((page) => { d.applyPosts(page); d.loadPosts.success() }),
        ),
    }),
  ),
)

import { ofType, mutationMap, fromRequest, apiResult } from 'synapse-storage/reactive'
import { exhaustMap, mergeMap } from 'rxjs/operators'

// create — single submit: exhaustMap (ignore double-submit), async body via prepare
createPost$ = this.effect((action$, _state$, { dispatcher: d }) =>
  action$.pipe(
    ofType(d.createPost),
    mutationMap({
      flatten: exhaustMap,
      loadingAction: () => d.createPost.loading(),
      errorAction: (err) => d.createPost.failure(getErrorMessage(err)),
      prepare: (payload) => buildCreateBody(this.api, payload),
      apiCall: (_payload, body) =>
        fromRequest(this.api.createPost.request({ body })).pipe(
          apiResult((post) => { d.createPost.success(); d.prependPost(post) }),
        ),
    }),
  ),
)

// delete — acts on different posts: mergeMap (parallel), no body
removePost$ = this.effect((action$, _state$, { dispatcher: d }) =>
  action$.pipe(
    ofType(d.removePost),
    mutationMap({
      flatten: mergeMap,
      errorAction: (err, id) => d.removePost.failure(getErrorMessage(err)),
      apiCall: (id) =>
        fromRequest(this.api.removePost.request({ id })).pipe(
          apiResult(() => d.dropPost(id)),
        ),
    }),
  ),
)

// ── Synchronously ──
const allKeys = storage.keys()
// ['name', 'age', 'role', 'active']

// ── Asynchronously ──
const allKeys = await storage.keys()

// Removes a key from the storage.
// After removal has(key) returns false, and keys() does not contain that key.

// ── Synchronously ──
storage.remove('role')
storage.has('role')   // false
storage.keys()        // ['name', 'age', 'active']

// ── Asynchronously ──
await storage.remove('role')

// Removes ALL keys. The state becomes an empty object {}.

// ── Synchronously ──
storage.clear()
storage.getState()   // {}
storage.keys()       // []

// ── Asynchronously ──
await storage.clear()

// Returns the state to its initial value (initialState from the config).

// ── Synchronously ──
storage.reset()
storage.getState()   // { name: 'Alice', age: 28, role: 'admin', active: true }

// ── Asynchronously ──
await storage.reset()

const storage = new MemoryStorage({
  name: 'example',
  initialState: { count: 0, label: 'hello' },
})

storage.set('count', 99)
storage.set('label', 'world')

// clear() — a full wipe
storage.clear()
storage.getState()   // {}
storage.keys()       // []

// reset() — back to initialState
storage.reset()
storage.getState()   // { count: 0, label: 'hello' }
storage.keys()       // ['count', 'label']

import { MemoryStorage, Selectors } from 'synapse-storage/core'
import { createSynapse } from 'synapse-storage/utils'
import { Dispatcher } from 'synapse-storage/reactive'

class AuthSelectors extends Selectors<AuthState> {
  readonly token = this.select((s) => s.token)
  readonly userId = this.select((s) => s.userId)
}

class AuthDispatcher extends Dispatcher<AuthState> {
  readonly login = this.action((store, userId: string) => {
    store.update((s) => { s.token = `jwt-${userId}`; s.userId = userId })
    return userId
  })
  readonly logout = this.action((store) => {
    store.update((s) => { s.token = null; s.userId = null })
  })
}

