import { MemoryStorage } from 'synapse-storage/core'
import { Dispatcher } from 'synapse-storage/reactive'

interface CounterState {
  value: number
  step: number
  history: number[]
}

const storage = new MemoryStorage<CounterState>({
  name: 'counter',
  initialState: { value: 0, step: 1, history: [] },
})
await storage.initialize()

class CounterDispatcher extends Dispatcher<CounterState> {
  readonly increment = this.action((store) => store.update((s) => { s.value += s.step }))
  readonly watchValue = this.watcher({ selector: (s) => s.value })
}

const dispatcher = new CounterDispatcher(storage)

class CounterDispatcher extends Dispatcher<CounterState> {
  // Simple action (no parameters)
  readonly increment = this.action((store) => {
    store.update((s) => { s.value += s.step })
  })

  // Action with a parameter (return = payload in the action stream)
  readonly setStep = this.action((store, newStep: number) => {
    store.set('step', newStep)
    return newStep
  })

  // Action with meta — arbitrary metadata (2nd argument of this.action)
  readonly reset = this.action(
    (store) => { store.reset() },
    { meta: { description: 'Reset to default values', dangerous: true } },
  )

  // Action with memoization — a repeated call with the same argument is skipped
  readonly setStepMemo = this.action(
    (store, step: number) => { store.set('step', step); return step },
    { memoize: (current, previous) => current === previous },
  )
}

class CounterDispatcher extends Dispatcher<CounterState> {
  // A pure intent: writes nothing to the store, the payload is passed further to effects.
  // description goes into meta.
  readonly pinged = this.signal<number>('Manual ping')
}

class PostsDispatcher extends Dispatcher<PostsState> {
  // the accessor points to the ApiRequestState cell in the state
  readonly loadPosts = this.apiActions<{ page: number }>((s) => s.api.postsRequest)
}

// Usage:
d.loadPosts({ page: 1 })      // init: status → idle, the intent goes to effects
d.loadPosts.loading()         // status → loading
d.loadPosts.success()         // status → success
d.loadPosts.failure('msg')    // status → error, error = 'msg'
d.loadPosts.reset()           // status → reset

// In an effect: we react to the INTENT to load (init), not to statuses
action$.pipe(ofType(d.loadPosts), /* ... start the request ... */)

// To react to a RESULT — listen for the specific phase explicitly:
action$.pipe(ofType(d.loadPosts.success), /* ... */)
action$.pipe(ofType(d.loadPosts.failure), /* ... */)

class CounterDispatcher extends Dispatcher<CounterState> {
  // Basic watcher — tracks a value
  readonly watchValue = this.watcher({ selector: (state) => state.value })

  // With shouldTrigger — filtering out false triggers
  readonly watchBigChanges = this.watcher({
    selector: (state) => state.value,
    shouldTrigger: (prev, current) => Math.abs((prev ?? 0) - current) >= 5,
  })

  // With notifyAfterSubscribe — call the callback immediately on subscribe
  readonly watchStep = this.watcher({
    selector: (state) => state.step,
    notifyAfterSubscribe: true,
  })
}

// Calling actions — through the instance's typed fields
dispatcher.increment()
dispatcher.setStep(5)
dispatcher.reset()

// Or through the dispatch registry
dispatcher.dispatch.reset.actionType  // '[counter]reset'
dispatcher.dispatch.reset.meta        // { description: '...', dangerous: true }

// Subscribing to watchers (RxJS Observable)
const sub = dispatcher.watchers.watchValue().subscribe((action) => {
  console.log('value:', action.payload)
})
sub.unsubscribe()

// Subscribing to ALL actions
dispatcher.actions.subscribe((action) => {
  console.log(action.type, action.payload)
})

// Cleanup
dispatcher.destroy()

const eventBusHandle = createEventBus({
  name: 'app-events',        // name (for singleton/debugging)
  autoCleanup: true,          // auto-cleanup of old events
  maxEvents: 1000,            // max stored events (default 1000)
})

// createEventBus returns a SynapseModule handle (lazy, PromiseLike) —
// the factory runs on the first await/ready()
const eventBus = await eventBusHandle

// The result:
// {
//   storage: ISyncStorage<EventBusState>   — the state storage
//   actions: EventBusActions               — typed actions
//   dispatcher: Dispatcher                 — the raw dispatcher
//   selectors: {}
//   destroy: () => Promise<void>           — cleanup
// }

// EventBusState:
// {
//   events: Record<string, EventBusEvent>
//   subscriptions: Record<string, SubscriptionInfo>
// }

const eventBus = await createEventBus({ name: 'my-bus' })

// Publishing an event
const result = await eventBus.actions.publish({
  event: 'USER_UPDATED',           // event type (string)
  data: { userId: 123, name: 'John' },  // arbitrary data
  metadata: {                       // optional metadata
    priority: 'high',               // 'low' | 'normal' | 'high'
    ttl: 60000,                     // event time-to-live (ms)
  },
})

// The result:
// {
//   eventId: string    — the unique event ID
//   event: string      — the event type
//   data: any          — the data
// }

// EventBusEvent (stored in storage):
// {
//   id: string
//   event: string
//   data: any
//   metadata: { ttl?: number | null, priority?: 'low' | 'normal' | 'high' }
//   timestamp: number
// }

// Subscribing to a specific event
const { subscriptionId, unsubscribe } = await eventBus.actions.subscribe({
  eventPattern: 'USER_UPDATED',    // exact match
  handler: (data, event) => {
    // data — event.data (the payload)
    // event — the full EventBusEvent object
    console.log(data)               // { userId: 123, name: 'John' }
    console.log(event.event)        // 'USER_UPDATED'
    console.log(event.timestamp)    // 1716633600000
  },
})

// Wildcard patterns
await eventBus.actions.subscribe({
  eventPattern: 'USER_*',          // all events starting with USER_
  handler: (data, event) => {      // USER_UPDATED, USER_DELETED, USER_CREATED...
    console.log(event.event, data)
  },
})

await eventBus.actions.subscribe({
  eventPattern: '*',               // ALL events
  handler: (data, event) => {
    console.log('Any event:', event.event)
  },
})

// Filter by priority
await eventBus.actions.subscribe({
  eventPattern: 'NOTIFICATION_*',
  handler: (data, event) => { ... },
  options: { priority: 'high' },   // only high-priority events
})

// Unsubscribe
unsubscribe()

// Get the history for an event type
const history = await eventBus.actions.getEventHistory({
  eventType: 'USER_UPDATED',      // the event type
  limit: 10,                       // max records (default 100)
})

// Returns EventBusEvent[] — sorted by timestamp (newest first)
// [
//   { id: '...', event: 'USER_UPDATED', data: {...}, timestamp: 1716633600000 },
//   { id: '...', event: 'USER_UPDATED', data: {...}, timestamp: 1716633500000 },
// ]

const subscriptions = await eventBus.actions.getActiveSubscriptions()

// Returns an array:
// [
//   {
//     id: string,          — the subscription ID
//     pattern: string,     — the pattern ('USER_*', '*', etc.)
//     options: {...},       — options (priority etc.)
//     createdAt: number,   — creation time
//   }
// ]

// Clear old events
await eventBus.actions.clearEvents({
  olderThan: 60000,                // remove events older than 60 seconds
})

// Clear all events
await eventBus.actions.clearEvents({})

// module-a.ts — publishes events
const bus = await eventBusHandle

export async function saveUser(user: User) {
  await api.saveUser(user)
  await bus.actions.publish({
    event: 'USER_SAVED',
    data: { userId: user.id },
    metadata: { priority: 'high' },
  })
}

// module-b.ts — listens for events
const bus = await eventBusHandle

bus.actions.subscribe({
  eventPattern: 'USER_SAVED',
  handler: (data) => {
    // Update the cache, send a notification, etc.
    console.log('User saved:', data.userId)
  },
})

// module-c.ts — listens for all USER_* events
bus.actions.subscribe({
  eventPattern: 'USER_*',
  handler: (data, event) => {
    analytics.track(event.event, data)
  },
})

