      </button>

      <ul>
        {(notes ?? []).map((note) => (
          <li key={note.id}>
            {note.text}
            <button onClick={() =>
              storage.update((s) => { s.notes = s.notes.filter((n) => n.id !== note.id) })
            }>x</button>
          </li>
        ))}
      </ul>
    </div>
  )
}

